  1→use std::collections::HashMap;
  2→use std::path::PathBuf;
  3→
  4→use clap::Parser;
  5→use slop_guard::{analyze_with_config, Hyperparameters, RULE_NAMES};
  6→
  7→#[derive(Parser)]
  8→#[command(
  9→    name = "slop-guard-calibrate",
 10→    about = "Calibrate slop-guard penalties against a human-written corpus"
 11→)]
 12→struct Cli {
 13→    /// Directory containing .txt corpus files
 14→    corpus_dir: PathBuf,
 15→
 16→    /// Output path for calibrated config JSON
 17→    #[arg(long, default_value = "calibrated.json")]
 18→    output: PathBuf,
 19→
 20→    /// Minimum word count to include a document
 21→    #[arg(long, default_value_t = 50)]
 22→    min_words: usize,
 23→}
 24→
 25→fn main() {
 26→    let cli = Cli::parse();
 27→
 28→    let hp = Hyperparameters::default();
 29→
 30→    // Collect .txt files
 31→    let entries: Vec<PathBuf> = std::fs::read_dir(&cli.corpus_dir)
 32→        .unwrap_or_else(|e| {
 33→            eprintln!("Error reading corpus dir {:?}: {e}", cli.corpus_dir);
 34→            std::process::exit(1);
 35→        })
 36→        .filter_map(|entry| {
 37→            let entry = entry.ok()?;
 38→            let path = entry.path();
 39→            if path.extension().and_then(|e| e.to_str()) == Some("txt") {
 40→                Some(path)
 41→            } else {
 42→                None
 43→            }
 44→        })
 45→        .collect();
 46→
 47→    if entries.is_empty() {
 48→        eprintln!("No .txt files found in {:?}", cli.corpus_dir);
 49→        std::process::exit(1);
 50→    }
 51→
 52→    // Per-rule support tracking: how many docs trigger each rule
 53→    let mut rule_support: HashMap<String, usize> = HashMap::new();
 54→    for name in RULE_NAMES {
 55→        rule_support.insert(name.to_string(), 0);
 56→    }
 57→    let mut total_docs = 0usize;
 58→
 59→    for path in &entries {
 60→        let text = match std::fs::read_to_string(path) {
 61→            Ok(t) => t,
 62→            Err(e) => {
 63→                eprintln!("Skipping {:?}: {e}", path);
 64→                continue;
 65→            }
 66→        };
 67→
 68→        let wc = text.split_whitespace().count();
 69→        if wc < cli.min_words {
 70→            continue;
 71→        }
 72→
 73→        total_docs += 1;
 74→        let result = analyze_with_config(&text, &hp);
 75→
 76→        for name in RULE_NAMES {
 77→            if let Some(&count) = result.counts.get(*name) {
 78→                if count > 0 {
 79→                    *rule_support.get_mut(*name).unwrap() += 1;
 80→                }
 81→            }
 82→        }
 83→    }
 84→
 85→    if total_docs == 0 {
 86→        eprintln!(
 87→            "No documents met the minimum word count ({}).",
 88→            cli.min_words
 89→        );
 90→        std::process::exit(1);
 91→    }
 92→
 93→    // Print support table to stderr
 94→    eprintln!("Corpus: {} documents from {:?}", total_docs, cli.corpus_dir);
 95→    eprintln!("{:<25} {:>8} {:>10}", "Rule", "Support", "Ratio");
 96→    eprintln!("{}", "-".repeat(45));
 97→
 98→    for name in RULE_NAMES {
 99→        let support = *rule_support.get(*name).unwrap();
100→        let ratio = support as f64 / total_docs as f64;
101→        eprintln!("{:<25} {:>8} {:>9.2}%", name, support, ratio * 100.0);
102→    }
103→
104→    // Apply fit_penalty: scale = clamp(1.5 - support_ratio, 0.5, 1.75)
105→    // magnitude = max(1, round(|base_penalty| * scale))
106→    // Result is always negative (penalty).
